   108→//
   109→//  shared_ptr
   110→//
   111→//  An enhanced relative of scoped_ptr with reference counted copy semantics.
   112→//  The object pointed to is deleted when the last shared_ptr pointing to it
   113→//  is destroyed or reset.
   114→//
   115→
   116→template<class T> class shared_ptr
   117→{
   118→private:
   119→
   120→    typedef shared_ptr<T> this_type;
   121→
   122→public:
   123→
   124→    typedef T element_type;
   125→    typedef T value_type;
   126→    typedef T * pointer;
   127→    typedef typename sofa::pbrpc::detail::shared_ptr_traits<T>::reference reference;
   128→
   129→    shared_ptr(): px(0), pn() // never throws in 1.30+
   130→    {
   131→    }
   132→
   133→    template<class Y>
   134→    explicit shared_ptr( Y * p ): px( p ), pn( p ) // Y must be complete
   135→    {
   136→        sofa::pbrpc::detail::sp_enable_shared_from_this( this, p, p );
   137→    }
   138→
   139→    //
   140→    // Requirements: D's copy constructor must not throw
   141→    //
   142→    // shared_ptr will release p by calling d(p)
   143→    //
   144→
   145→    template<class Y, class D> shared_ptr(Y * p, D d): px(p), pn(p, d)
   146→    {
   147→        sofa::pbrpc::detail::sp_enable_shared_from_this( this, p, p );
   148→    }
   149→
   150→    // As above, but with allocator. A's copy constructor shall not throw.
   151→
   152→    template<class Y, class D, class A> shared_ptr( Y * p, D d, A a ): px( p ), pn( p, d, a )
   153→    {
   154→        sofa::pbrpc::detail::sp_enable_shared_from_this( this, p, p );
   155→    }
   156→
   157→//  generated copy constructor, destructor are fine...
   158→
   159→    template<class Y>
   160→    explicit shared_ptr(weak_ptr<Y> const & r): pn(r.pn) // may throw
   161→    {
   162→        // it is now safe to copy r.px, as pn(r.pn) did not throw
   163→        px = r.px;
   164→    }
   165→
   166→    template<class Y>
   167→    shared_ptr( weak_ptr<Y> const & r, sofa::pbrpc::detail::sp_nothrow_tag ): px( 0 ), pn( r.pn, sofa::pbrpc::detail::sp_nothrow_tag() ) // never throws
   168→    {
   169→        if( !pn.empty() )
   170→        {
   171→            px = r.px;
   172→        }
   173→    }
   174→
   175→    template<class Y>
   176→    shared_ptr( shared_ptr<Y> const & r, typename sofa::pbrpc::detail::sp_enable_if_convertible<Y,T>::type = sofa::pbrpc::detail::sp_empty() )
   177→    : px( r.px ), pn( r.pn ) // never throws
   178→    {
   179→    }
   180→
   181→    // aliasing
   182→    template< class Y >
   183→    shared_ptr( shared_ptr<Y> const & r, T * p ): px( p ), pn( r.pn ) // never throws
   184→    {
   185→    }
   186→
   187→    template<class Y>
   188→    shared_ptr(shared_ptr<Y> const & r, sofa::pbrpc::detail::static_cast_tag): px(static_cast<element_type *>(r.px)), pn(r.pn)
   189→    {
   190→    }
   191→
   192→    template<class Y>
   193→    shared_ptr(shared_ptr<Y> const & r, sofa::pbrpc::detail::const_cast_tag): px(const_cast<element_type *>(r.px)), pn(r.pn)
   194→    {
   195→    }
   196→
   197→    template<class Y>
   198→    shared_ptr(shared_ptr<Y> const & r, sofa::pbrpc::detail::dynamic_cast_tag): px(dynamic_cast<element_type *>(r.px)), pn(r.pn)
   199→    {
   200→        if(px == 0) // need to allocate new counter -- the cast failed
   201→        {
   202→            pn = sofa::pbrpc::detail::shared_count();
   203→        }
   204→    }
   205→
   206→    template<class Y>
   207→    shared_ptr(shared_ptr<Y> const & r, sofa::pbrpc::detail::polymorphic_cast_tag): px(dynamic_cast<element_type *>(r.px)), pn(r.pn)
   208→    {
   209→        if(px == 0)
   210→        {
   211→            throw std::bad_cast();
   212→        }
   213→    }
   214→
   215→    // assignment
   216→
   217→    shared_ptr & operator=( shared_ptr const & r ) // never throws
   218→    {
   219→        this_type(r).swap(*this);
   220→        return *this;
   221→    }
   222→
   223→    template<class Y>
   224→    shared_ptr & operator=(shared_ptr<Y> const & r) // never throws
   225→    {
   226→        this_type(r).swap(*this);
   227→        return *this;
   228→    }
   229→
   230→
   231→
   232→    void reset() // never throws in 1.30+
   233→    {
   234→        this_type().swap(*this);
   235→    }
   236→
   237→    template<class Y> void reset(Y * p) // Y must be complete
   238→    {
   239→        assert(p == 0 || p != px); // catch self-reset errors
   240→        this_type(p).swap(*this);
   241→    }
   242→
   243→    template<class Y, class D> void reset( Y * p, D d )
   244→    {
   245→        this_type( p, d ).swap( *this );
   246→    }
   247→
   248→    template<class Y, class D, class A> void reset( Y * p, D d, A a )
   249→    {
   250→        this_type( p, d, a ).swap( *this );
   251→    }
   252→
   253→    template<class Y> void reset( shared_ptr<Y> const & r, T * p )
   254→    {
   255→        this_type( r, p ).swap( *this );
   256→    }
   257→
   258→    reference operator* () const // never throws
   259→    {
   260→        assert(px != 0);
   261→        return *px;
   262→    }
   263→
   264→    T * operator-> () const // never throws
   265→    {
   266→        assert(px != 0);
   267→        return px;
   268→    }
   269→
   270→    T * get() const // never throws
   271→    {
   272→        return px;
   273→    }
   274→
   275→// implicit conversion to "bool"
   276→#include <sofa/pbrpc/smart_ptr/detail/operator_bool.hpp>
   277→
   278→    bool unique() const // never throws
   279→    {
   280→        return pn.unique();
   281→    }
   282→
   283→    long use_count() const // never throws
   284→    {
   285→        return pn.use_count();
   286→    }
   287→
   288→    void swap(shared_ptr<T> & other) // never throws
   289→    {
   290→        std::swap(px, other.px);
   291→        pn.swap(other.pn);
   292→    }
   293→
   294→    template<class Y> bool owner_before( shared_ptr<Y> const & rhs ) const
   295→    {
   296→        return pn < rhs.pn;
